}

function setVideo() {
   let videoSlug = location.hash.substring(1);
   const requestedVideoIid = videoHash[videoSlug];
   Object.values(videoHash).forEach(iid => {
        if (iid === requestedVideoIid) {
            zPortal.block.show(iid);
        } else {
            zPortal.block.hide(iid);
        }
   });
}

// Set proper video on page load
setVideo();

// Set proper video on nav link click
function locationHashChanged (e) {
   if (location.href.includes('zuar-training-videos')) {
       setVideo();
   }
}
window.onhashchange = locationHashChanged;
